using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ───────────────────────── AddItem ─────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 3, price: 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_Throws()
    {
        _cart.AddItem(null!, quantity: 1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_Throws()
    {
        _cart.AddItem("", quantity: 1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_ZeroQuantity_Throws()
    {
        _cart.AddItem("SKU-001", quantity: 0, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativeQuantity_Throws()
    {
        _cart.AddItem("SKU-001", quantity: -1, price: 5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativePrice_Throws()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: -10.00m);
    }

    // ───────────────────── RemoveItem ──────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalBecomesZero()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 7.50m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentSku_Throws()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveItem_NullSku_Throws()
    {
        _cart.RemoveItem(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveItem_EmptySku_Throws()
    {
        _cart.RemoveItem("");
    }

    // ─────────────────── CalculateTotal ────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsRemainingItems()
    {
        _cart.AddItem("A", quantity: 1, price: 100.00m);
        _cart.AddItem("B", quantity: 2, price: 50.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(100.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_LargeQuantity_CalculatesCorrectly()
    {
        _cart.AddItem("BULK", quantity: 1000, price: 0.99m);

        Assert.AreEqual(990.00m, _cart.CalculateTotal());
    }

    // ──────────────────── ApplyCoupon ──────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_NullCode_Throws()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        _cart.ApplyCoupon("");
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ──────────────── Integration / Edge Cases ─────────────

    [TestMethod]
    public void AddThenRemoveAllItems_TotalIsZero()
    {
        _cart.AddItem("A", quantity: 1, price: 25.00m);
        _cart.AddItem("B", quantity: 1, price: 35.00m);

        _cart.RemoveItem("A");
        _cart.RemoveItem("B");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_ThenAddMoreItems_TotalReflectsBoth()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);
        _cart.ApplyCoupon("SAVE10");

        decimal totalAfterCoupon = _cart.CalculateTotal();

        _cart.AddItem("SKU-002", quantity: 1, price: 50.00m);

        Assert.IsTrue(_cart.CalculateTotal() > totalAfterCoupon,
            "Adding items after a coupon should increase the total.");
    }

    [TestMethod]
    public void CalculateTotal_CalledMultipleTimes_ReturnsSameValue()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 15.00m);

        decimal first = _cart.CalculateTotal();
        decimal second = _cart.CalculateTotal();

        Assert.AreEqual(first, second, "CalculateTotal should be idempotent.");
    }
}

